FUNCTION_BLOCK FB_HexDigitAnalyzer
VAR_INPUT
    InputNumber : INT; // Input integer value
END_VAR_INPUT

VAR_OUTPUT
    Thousands : INT; // Thousands place digit
    Hundreds : INT; // Hundreds place digit
    Tens : INT; // Tens place digit
    Ones : INT; // Ones place digit
    Min : INT; // Minimum non-zero digit
    error : BOOL; // Error state indicator
    status : WORD; // Error code
END_VAR_OUTPUT

VAR
    minValue : INT; // Variable to hold the minimum non-zero digit
    digit : INT; // Temporary variable for digit extraction
END_VAR

// Input Validation
IF (InputNumber < 0) OR (InputNumber > 9999) THEN
    error := TRUE;
    status := 16#8001; // Input number out of valid range
    Thousands := 0;
    Hundreds := 0;
    Tens := 0;
    Ones := 0;
    Min := 0;
ELSE
    error := FALSE;
    status := 0; // No error

    // Digit Separation Logic
    Thousands := InputNumber / 1000;
    Hundreds := (InputNumber MOD 1000) / 100;
    Tens := (InputNumber MOD 100) / 10;
    Ones := InputNumber MOD 10;

    // Minimum Value Detection
    minValue := 32767; // Initialize minValue to maximum possible INT value

    // Check each digit for non-zero and find minimum
    FOR digit := 1 TO 4 DO
        CASE digit OF
            1: // Check Thousands
                IF Thousands > 0 THEN
                    minValue := minimal(minValue, Thousands);
                END_IF;
            2: // Check Hundreds
                IF Hundreds > 0 THEN
                    minValue := minimal(minValue, Hundreds);
                END_IF;
            3: // Check Tens
                IF Tens > 0 THEN
                    minValue := minimal(minValue, Tens);
                END_IF;
            4: // Check Ones
                IF Ones > 0 THEN
                    minValue := minimal(minValue, Ones);
                END_IF;
        END_CASE;
    END_FOR;

    // Set Min output based on minValue
    IF minValue = 32767 THEN
        Min := 0; // All digits were zero
    ELSE
        Min := minValue; // Found minimum non-zero digit
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION minimal(IN1: INT, IN2: INT) : INT
VAR
    result : INT; // Variable to hold the result
END_VAR

// Compare two integers and return the smaller one
IF IN1 < IN2 THEN
    result := IN1;
ELSE
    result := IN2;
END_IF;

minimal := result; // Return the result
END_FUNCTION

